+    // Title
+    let text = theme::text_bold();
+    let title_line = format!(" {text}{title}{RESET}");
+    let title_vis = title.len() + 1;
+    let pad = w.saturating_sub(title_vis);
+    lines.push(format!(
+        "{color}{mid_l}{title_line}{}{color}{mid_r}{RESET}",
