+    let right_block = Block::bordered()
+        .border_type(BorderType::Rounded)
+        .title(" Traffic ");
+    Paragraph::new(request_summary)
+        .block(right_block)
+        .style(if snapshot.requests_5xx > 0 {
+            warn_style
+        } else {
